import glob
import os
from pathlib import Path
from typing import List, Tuple

import numpy as np
from PIL import Image
from torch.utils import data

num_classes = 2
ignore_label = 255
_RELATIVE_DATA_DIR = 'LA-dataset/LA-2D'
_DEFAULT_RESIZE = (224, 224)


def _resolve_root(data_path: str) -> Path:
    candidates = []
    if data_path:
        candidates.append(Path(data_path).expanduser() / _RELATIVE_DATA_DIR)
    # Fallback to repository root if data_path/root combination does not exist
    repo_root = Path(__file__).resolve().parents[1]
    candidates.append(repo_root / _RELATIVE_DATA_DIR)
    for candidate in candidates:
        if candidate.exists():
            return candidate
    raise FileNotFoundError(
        f"Could not locate LA dataset. Checked: {[str(c) for c in candidates]}"
    )


def _make_dataset(split: str, root: Path) -> List[Tuple[str, str, str]]:
    if split not in {"train", "val", "test"}:
        raise ValueError(f"Unsupported split '{split}' for LA dataset")
    split_dir = "train" if split == "train" else "test"
    images_dir = root / split_dir / "images"
    masks_dir = root / split_dir / "masks"
    if not images_dir.exists() or not masks_dir.exists():
        raise FileNotFoundError(f"LA dataset split '{split_dir}' is missing images or masks: {root}")
    img_paths = sorted(glob.glob(str(images_dir / "*.png")))
    items: List[Tuple[str, str, str]] = []
    for img_path in img_paths:
        file_name = os.path.basename(img_path)
        mask_path = masks_dir / file_name
        if not mask_path.exists():
            continue
        items.append((img_path, str(mask_path), file_name))
    if not items:
        raise RuntimeError(f"Found 0 LA slices for split '{split}' in {root}")
    return items


def _load_uint16_png(path: str) -> Image.Image:
    img = Image.open(path)
    img_arr = np.array(img, dtype=np.uint16)
    img.close()
    if img_arr.size == 0:
        raise RuntimeError(f"Empty image encountered at {path}")
    # Scale to 8-bit for compatibility with ImageNet normalization
    if img_arr.max() > 0:
        img_arr = (img_arr.astype(np.float32) / 65535.0) * 255.0
    img_arr = img_arr.clip(0, 255).astype(np.uint8)
    return Image.fromarray(img_arr).convert('RGB')


def _load_mask(path: str) -> Image.Image:
    mask = Image.open(path)
    mask = mask.convert('L')
    return mask


class LA2D(data.Dataset):
    def __init__(self, quality, mode, data_path='', joint_transform=None,
                 sliding_crop=None, transform=None, target_transform=None,
                 subset=False, resize_to=None):
        del quality, sliding_crop, subset  # Unused but kept for API compatibility
        self.num_classes = num_classes
        self.ignore_label = ignore_label
        self.root = _resolve_root(data_path)
        self.mode = mode
        self.joint_transform = joint_transform
        self.transform = transform
        self.target_transform = target_transform
        if resize_to is not None and len(resize_to) == 2:
            self.resize_to = tuple(resize_to)
        else:
            self.resize_to = _DEFAULT_RESIZE
        split = 'train' if mode == 'train' else 'val'
        self.imgs = _make_dataset(split, self.root)
        print(f"LA2D [{split}] -> using {len(self.imgs)} slices from {self.root}")

    def __getitem__(self, index):
        img_path, mask_path, im_name = self.imgs[index]
        img = _load_uint16_png(img_path)
        mask = _load_mask(mask_path)
        if self.resize_to is not None:
            img = img.resize(self.resize_to, Image.BILINEAR)
            mask = mask.resize(self.resize_to, Image.NEAREST)
        if self.joint_transform is not None:
            img, mask = self.joint_transform(img, mask)
        if self.transform is not None:
            img = self.transform(img)
        if self.target_transform is not None:
            mask = self.target_transform(mask)
        return img, mask, (img_path, mask_path, im_name)

    def __len__(self):
        return len(self.imgs)
